#include <stdio.h>
#include <stdlib.h>

#define MAX 100

struct MinHeap {
    int arr[MAX];
    int size;
};

void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

void heapifyUp(struct MinHeap *heap, int index) {
    while (index > 0) {
        int parent = (index - 1) / 2;

        if (heap->arr[parent] > heap->arr[index]) {
            swap(&heap->arr[parent], &heap->arr[index]);
            index = parent;
        } else {
            break;
        }
    }
}

void heapifyDown(struct MinHeap *heap, int index) {
    while (1) {
        int left = 2 * index + 1;
        int right = 2 * index + 2;
        int smallest = index;

        if (left < heap->size &&
            heap->arr[left] < heap->arr[smallest])
            smallest = left;

        if (right < heap->size &&
            heap->arr[right] < heap->arr[smallest])
            smallest = right;

        if (smallest != index) {
            swap(&heap->arr[index], &heap->arr[smallest]);
            index = smallest;
        } else {
            break;
        }
    }
}

void insert(struct MinHeap *heap, int value) {
    if (heap->size == MAX) {
        printf("Heap full\n");
        return;
    }

    heap->arr[heap->size] = value;
    heapifyUp(heap, heap->size);
    heap->size++;
}

int deleteMin(struct MinHeap *heap) {
    if (heap->size == 0) {
        printf("Heap empty\n");
        return -1;
    }

    int min = heap->arr[0];

    heap->arr[0] = heap->arr[heap->size - 1];
    heap->size--;

    heapifyDown(heap, 0);

    return min;
}

void display(struct MinHeap *heap) {
    if (heap->size == 0) {
        printf("Heap empty.\n");
        return;
    }

    for (int i = 0; i < heap->size; i++) {
        printf("%d ", heap->arr[i]);
    }
    printf("\n");
}

int main() {
    struct MinHeap heap;
    heap.size = 0;

    int n, val, delChoice;

    printf("Enter no of elements: ");
    scanf("%d", &n);

    printf("Enter elements:\n");
    for (int i = 0; i < n; i++) {
        scanf("%d", &val);
        insert(&heap, val);
    }

    printf("\nMin Heap: ");
    display(&heap);

    printf("Delete minimum element? : ");
    scanf("%d", &delChoice);

    if (delChoice == 1) {
        int deleted = deleteMin(&heap);
        printf("Deleted element: %d\n", deleted);

        printf("after deletion: ");
        display(&heap);
    }

    return 0;
}

