    int data;
    struct node* forward[MAX];
};

struct node* header;

struct node* createnode(int val) {
    struct node* nn = (struct node*)malloc(sizeof(struct node));
    nn->data = val;

    for (int i = 0; i < MAX; i++) {
        nn->forward[i] = NULL;
    }

    return nn;
}

int randlevel() {
    int level = 1;

    while ((rand() % 2 == 0) && level < MAX) {
        level++;
    }

    return level;
}

void insert(int val) {
    struct node* update[MAX];
    struct node* x = header;

    for (int i = MAX - 1; i >= 0; i--) {
        while (x->forward[i] != NULL &&
               x->forward[i]->data < val) {
            x = x->forward[i];
        }
        update[i] = x;
    }

    x = x->forward[0];

    if (x == NULL || x->data != val) {
        struct node* p = createnode(val);
        int level = randlevel();

        for (int i = 0; i < level; i++) {
            p->forward[i] = update[i]->forward[i];
            update[i]->forward[i] = p;
        }
    }
}

