#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct node {
    struct node *children[26];
    int EOW;
} node;

node *root = NULL;

node* createNode() {
    node* newNode = (node*)malloc(sizeof(node));

    for (int i = 0; i < 26; i++) {
        newNode->children[i] = NULL;
    }

    newNode->EOW = 0;
    return newNode;
}

void suffix(char word[], char original[]) {
    int pos = (word - original) + 1;
    node *p = root;

    for (int i = 0; word[i] != '\0'; i++) {
        int idx = word[i] - 'a';

        if (idx < 0 || idx >= 26) {
            printf("Only lowercase letter \n");
            return;
        }

        if (p->children[idx] == NULL) {
            p->children[idx] = createNode();
        }

        p = p->children[idx];
    }

    p->EOW = pos;
}

void insert(char word[]) {
    int n = strlen(word);

    for (int i = 0; i < n; i++) {
        suffix(word + i, word);
    }
}

void display(node* q, int level) {
    for (int i = 0; i < 26; i++) {
        if (q->children[i] != NULL) {
            for (int j = 0; j < level; j++) {
                printf(" ");
            }

            printf("%c", i + 'a');

            if (q->children[i]->EOW != 0) {
                printf(" (%d)", q->children[i]->EOW - 1);
            }

            printf("\n");

            display(q->children[i], level + 1);
        }
    }
}

int main() {
    char word[100];

    root = createNode();

    printf("Enter a lowercase word: ");
    scanf("%s", word);

    insert(word);

    printf("\nSuffix Trie:\n");
    display(root, 0);

    return 0;
}

