struct tnode* makeNode(int x) {
    struct tnode* n = (struct tnode*)malloc(sizeof(struct tnode));
    n->value = x;
    n->lflag = 1;
    n->rflag = 1;
    n->lptr = NULL;
    n->rptr = NULL;
    return n;
}

struct tnode* insertNode(struct tnode* root, int x) {
    struct tnode* n = makeNode(x);

    if (root == NULL)
        return n;

    struct tnode* cur = root;

    while (1) {
        if (x < cur->value) {
            if (cur->lflag == 0) {
                cur = cur->lptr;
            } else {
                n->lptr = cur->lptr;
                n->rptr = cur;
                cur->lptr = n;
                cur->lflag = 0;
                break;
            }
        } else {
            if (cur->rflag == 0) {
                cur = cur->rptr;
            } else {
                n->rptr = cur->rptr;
                n->lptr = cur;
                cur->rptr = n;
                cur->rflag = 0;
                break;
            }
        }
    }

    return root;
}

void inorderThreaded(struct tnode* root) {
    if (root == NULL) {
        printf("Tree is empty.\n");
        return;
    }

    struct tnode* cur = root;

    while (cur->lflag == 0)
        cur = cur->lptr;

    while (cur != NULL) {
        printf("%d ", cur->value);

        if (cur->rflag == 1) {
            cur = cur->rptr;
        } else {
            cur = cur->rptr;
            while (cur != NULL && cur->lflag == 0)
                cur = cur->lptr;
        }
    }
}

void preorderThreaded(struct tnode* root) {
    if (root == NULL) {
        printf("Tree is empty.\n");
        return;
    }

    struct tnode* cur = root;

    while (cur != NULL) {
        printf("%d ", cur->value);

        if (cur->lflag == 0) {
            cur = cur->lptr;
        } else if (cur->rflag == 0) {
            cur = cur->rptr;
        } else {
            while (cur != NULL && cur->rflag == 1)
                cur = cur->rptr;

            if (cur != NULL)
                cur = cur->rptr;
        }
    }
}

int main() {
    struct tnode* root = NULL;
    int n, val, choice;

    printf("Enter no of nodes: ");
    scanf("%d", &n);

    if (n < 1 || n > 1000) {
        printf(" a lot of no of nodes.\n");
        return 0;
    }

    printf("Enter node's values:\n");
    for (int i = 0; i < n; i++) {
        scanf("%d", &val);
        root = insertNode(root, val);
    }

    printf("\nChoose traversal:\n");
    printf("Inorder\n");
    printf("Preorder\n");
    scanf("%d", &choice);

    if (choice == 1) {
        printf("Inorder Traversal: ");
        inorderThreaded(root);
    } else if (choice == 2) {
        printf("Preorder Traversal: ");
        preorderThreaded(root);
    } else {
        printf("choice is invalid\n");
    }

    printf("\n");

    return 0;
