#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct TrieNode {
    struct TrieNode *child[26];
    int eow;
};

struct TrieNode *root = NULL;

struct TrieNode* newNode() {
    struct TrieNode *p = (struct TrieNode*)malloc(sizeof(struct TrieNode));

    for (int i = 0; i < 26; i++) {
        p->child[i] = NULL;
    }

    p->eow = 0;
    return p;
}

void insert(char word[]) {
    struct TrieNode *temp = root;

    for (int i = 0; word[i] != '\0'; i++) {
        int idx = word[i] - 'a';

        if (idx < 0 || idx >= 26) {
            printf("Only lowercase letters.\n");
            return;
        }

        if (temp->child[idx] == NULL) {
            temp->child[idx] = newNode();
        }

        temp = temp->child[idx];
    }

    temp->eow = 1;
}

int search(char word[]) {
    struct TrieNode *temp = root;

    for (int i = 0; word[i] != '\0'; i++) {
        int idx = word[i] - 'a';

        if (idx < 0 || idx >= 26) {
            return 0;
        }

        if (temp->child[idx] == NULL) {
            return 0;
        }

        temp = temp->child[idx];
    }

    return temp->eow;
}

void display(struct TrieNode *q, int level) {
    for (int i = 0; i < 26; i++) {
        if (q->child[i] != NULL) {
            for (int j = 0; j < level; j++) {
                printf(" ");
            }

            printf("%c", i + 'a');

            if (q->child[i]->eow == 1) {
                printf("*");
            }

            printf("\n");

            display(q->child[i], level + 1);
        }
    }
}

